mapper.select:
SELECT id, user_id AS userId, email, purpose, CASE WHEN used = 1 THEN 'USED' WHEN expired_at < NOW() THEN 'EXPIRED' ELSE 'PENDING' END AS status, used, expired_at AS expiredAt, used_at AS usedAt, created_at AS createdAt FROM email_verification
AND email LIKE CONCAT('%', #{email}, '%') AND purpose = #{purpose} AND used = 1 AND used = 0 AND expired_at < NOW() AND used = 0 AND expired_at >= NOW()
ORDER BY id DESC LIMIT #{limit}
